var sinkBytes []byte

func BenchmarkEncode(b *testing.B) {
    for _, size := range []int{64, 1024, 65536} {
        b.Run(fmt.Sprintf("%dB", size), func(b *testing.B) {
            data := makeData(size)
            b.SetBytes(int64(size))
            b.ResetTimer()
            for i := 0; i < b.N; i++ {
                sinkBytes = encode(data)
            }
        })
    }
}
